import React from 'react';

function newContact(props){
    const {userData} = props;
    return (
        <div className="newContact-container">
            {userData && (
                <div className="newContact">
                    <form>
                        <input></input>
                    </form>
                </div>
            )}
        </div>
    );
}

export default newContact;
